const items = $input.all();
const results = [];

for (const item of items) {
  const role = $("Loop Roles").item.json.currentRole;
  let jobResults = item.json.data || [];

  // Fallback: If no jobs found, create a generic but accurate role-specific job
  if (jobResults.length === 0) {
    jobResults = [{
      job_title: `${role} Specialist`,
      employer_name: "Industry Lead",
      job_city: "Remote",
      job_country: "India",
      job_description: `Exciting opportunity for a ${role} to join a growing team.`,
      job_apply_link: `https://www.linkedin.com/jobs/search/?keywords=${encodeURIComponent(role)}&location=India`
    }];
  }

  let count = 0;
  for (const job of jobResults) {
    if (count >= 3) break; // Increased to 3 jobs per role

    let applyLink = "";
    const allLinks = [
      job.job_apply_link,
      job.job_google_link,
      ...(job.apply_options || []).map(o => o.link)
    ].filter(Boolean);

    const linkedin = allLinks.find(l => l && l.includes("linkedin.com"));
    const naukri = allLinks.find(l => l && l.includes("naukri.com"));
    const indeed = allLinks.find(l => l && l.includes("indeed.com"));

    if (linkedin) applyLink = linkedin;
    else if (naukri) applyLink = naukri;
    else if (indeed) applyLink = indeed;
    else {
      const q = encodeURIComponent(role);
      applyLink = `https://www.linkedin.com/jobs/search/?keywords=${q}&location=India`;
    }

    const skills = [];
    const skillKeywords = [
      // Tech
      "Python", "React", "JavaScript", "TypeScript", "Node.js", "SQL", "AWS", "Docker", "Java", "Machine Learning", "Next.js", "MongoDB",
      // Design
      "Figma", "UI/UX", "Adobe XD", "Sketch",
      // Engineering (Civil/Mech/Elec)
      "AutoCAD", "SolidWorks", "MATLAB", "Revit", "STAAD Pro", "Circuit Design", "PLC", "Thermodynamics",
      // Business/Finance
      "Excel", "Power BI", "Tableau", "Agile", "Scrum", "Financial Modeling", "Corporate Finance", "QuickBooks", "Tally", "GST",
      // HR/Management
      "Recruitment", "Payroll", "Onboarding", "HRIS", "Labor Laws", "Talent Acquisition", "CRM", "Social Media", "SEO"
    ];

    const jobText = (
      (job.job_title || "") + " " +
      (job.job_description || "") + " " +
      (job.job_highlights?.Qualifications?.join(" ") || "")
    ).toLowerCase();

    for (const skill of skillKeywords) {
      if (jobText.includes(skill.toLowerCase())) {
        skills.push(skill);
      }
    }

    // Ensure at least 2 skills are shown
    if (skills.length < 2) {
       const roleSkills = {
         "Software Engineer": ["Python", "JavaScript"],
         "Web Developer": ["React", "Node.js"],
         "Civil Engineer": ["AutoCAD", "Project Management"],
         "Mechanical Engineer": ["SolidWorks", "CAD"],
         "Electrical Engineer": ["Circuit Design", "PLC"],
         "HR Manager": ["Recruitment", "Employee Relations"],
         "Banking": ["Risk Management", "Customer Service"],
         "Accountant": ["Tally", "Excel"],
         "Financial Analyst": ["Excel", "Financial Modeling"],
         "Marketing Manager": ["SEO", "Social Media"]
       };
       const fallbacks = roleSkills[role] || ["Teamwork", "Communication"];
       fallbacks.forEach(s => { if (!skills.includes(s)) skills.push(s); });
    }

    results.push({
      role: role,
      job_title: job.job_title || "Job Opening",
      company: job.employer_name || "Company",
      location: job.job_city 
                ? job.job_city + ", " + job.job_country 
                : "India",
      skills: skills.slice(0, 5),
      apply_link: applyLink
    });

    count++;
  }
}

return [{ json: { jobs: results } }];
